sql:
SELECT e.encounter_id, e.encounter_code, d.difficulty_level 
FROM encounters e 
JOIN difficulty_levels d ON e.difficulty_level = d.difficulty_level;

SELECT gm_name
FROM game_masters
WHERE gm_id IN (
    SELECT gm_id 
    FROM unbalanced_scenarios
);

external_knowledge:
- A balanced scenario likely refers to a scenario with evenly matched players and challenges; 
- An unbalanced scenario refers to a scenario with unevenly matched players and challenges; 
- Difficulty level is a measure of how hard the encounter is, often categorized as Easy, Medium, or Hard; 
- The success rate is a measure of how often players succeed in the encounter; 
- Average damage is a measure of the average amount of damage dealt in the encounter.

sql:
SELECT log_id
FROM encounter_logs
WHERE damage_dealt = (
    SELECT MAX(damage_dealt)
    FROM encounter_logs
);

SELECT player_id, AVG(xp_earned) AS average_xp, SUM(xp_earned) AS total_xp
FROM encounter_logs
GROUP BY player_id;

SELECT gm_id, email, created_at, updated_at, is_admin, password_hash
FROM game_masters
WHERE gm_name = 'Bob Williams';

SELECT COUNT(*)
FROM encounters
WHERE encounter_code = 'LA' AND difficulty_level != 'Easy';

SELECT e.encounter_id, e.encounter_code, d.difficulty_level, e.xp_value * d.xp_multiplier AS adjusted_xp_value
FROM encounters e
JOIN difficulty_levels d ON e.difficulty_level = d.difficulty_level;

SELECT 
    (SELECT AVG(ave_damage) FROM balanced_scenarios) - 
    (SELECT AVG(ave_damage) FROM unbalanced_scenarios) AS damage_difference;

SELECT gm_name, email
FROM game_masters
ORDER BY gm_name;
